// Drives the Dart implementation against the language-neutral contract in
// conformance/vectors.json and conformance/semantic_vectors.json (generated by
// the Zig reference). Every vector must reproduce in both directions.
//
// Run from the dart/ directory (CWD = dart/): the corpus is read from
// ../conformance/*.json. Prints a summary and exits nonzero on any failure.

import 'dart:convert' show jsonDecode, utf8;
import 'dart:io';
import 'dart:typed_data';

import 'package:struple/struple.dart';

int _failures = 0;
int _checks = 0;

void _check(bool ok, String what) {
  _checks++;
  if (!ok) {
    _failures++;
    stderr.writeln('FAIL: $what');
  }
}

List<dynamic> _loadCorpus(String name) {
  final text = File('../conformance/$name').readAsStringSync();
  final v = jsonDecode(text);
  if (v is! List) {
    throw StateError('$name is not an array');
  }
  return v;
}

// The malformed corpus is an object { description, cases: [ {hex, item, note} ] }
// (unlike vectors.json, which is a top-level array), so it needs its own loader.
List<dynamic> _loadMalformed() {
  final text = File('../conformance/malformed.json').readAsStringSync();
  final v = jsonDecode(text);
  if (v is! Map || v['cases'] is! List) {
    throw StateError('malformed.json is not an object with a cases array');
  }
  return v['cases'] as List;
}

String _toHex(Uint8List b) {
  final sb = StringBuffer();
  for (final x in b) {
    sb.write(x.toRadixString(16).padLeft(2, '0'));
  }
  return sb.toString();
}

Uint8List _fromHex(String s) {
  final out = Uint8List(s.length ~/ 2);
  for (var i = 0; i < out.length; i++) {
    out[i] = int.parse(s.substring(i * 2, i * 2 + 2), radix: 16);
  }
  return out;
}

// buildInto interprets a build op (a one-key JSON object) into encoded bytes —
// mirrors the Zig generator and the other languages' conformance tests. The op
// is read from dart:convert jsonDecode, so its number/string values arrive as
// native Dart objects; all precision-sensitive values are quoted strings.
void _buildInto(Writer w, Map<String, dynamic> op) {
  if (op.length != 1) {
    throw StateError('op must be a one-key object');
  }
  final key = op.keys.first;
  final val = op.values.first;
  switch (key) {
    case 'nil':
      w.appendNil();
    case 'undef':
      w.appendUndefined();
    case 'bool':
      w.appendBool(val == true);
    case 'int':
      w.appendBigIntValue(BigInt.parse(val as String));
    case 'float64':
      w.appendF64(_opFloat(val));
    case 'float32':
      w.appendF32(_opFloat(val));
    case 'decimal':
      w.appendDecimalString(val as String);
    case 'timestamp':
      w.appendTimestamp(int.parse(val as String));
    case 'uuid':
      final raw = _fromHex(val as String);
      if (raw.length != 16) {
        throw StateError('uuid must be 16 bytes, got ${raw.length}');
      }
      w.appendUuid(raw);
    case 'string':
      w.appendString(utf8.encode(val as String));
    case 'bytes':
      w.appendBytes(_fromHex(val as String));
    case 'array':
      final child = Writer();
      for (final item in (val as List)) {
        _buildInto(child, (item as Map).cast<String, dynamic>());
      }
      w.appendArray(child.bytes());
    case 'set':
      final elems = <Uint8List>[];
      for (final item in (val as List)) {
        final ep = Writer();
        _buildInto(ep, (item as Map).cast<String, dynamic>());
        elems.add(ep.bytes());
      }
      w.appendSet(elems);
    case 'map':
      final entries = <List<Uint8List>>[];
      for (final pair in (val as List)) {
        final p = pair as List;
        final kp = Writer();
        _buildInto(kp, (p[0] as Map).cast<String, dynamic>());
        final vp = Writer();
        _buildInto(vp, (p[1] as Map).cast<String, dynamic>());
        entries.add([kp.bytes(), vp.bytes()]);
      }
      w.appendMap(entries);
    default:
      throw StateError('unknown op "$key"');
  }
}

double _opFloat(dynamic v) {
  if (v is num) return v.toDouble();
  throw StateError('expected number op value, got $v');
}

Uint8List _buildOne(Map<String, dynamic> op) {
  final w = Writer();
  _buildInto(w, op);
  return w.bytes();
}

void main() {
  final vectors = _loadCorpus('vectors.json');
  _check(vectors.isNotEmpty, 'corpus has vectors');

  // 1. JSON encode: fromJson(json) == bytes.
  var jsonCount = 0;
  for (final raw in vectors) {
    final v = (raw as Map).cast<String, dynamic>();
    if (!v.containsKey('json')) continue;
    jsonCount++;
    final json = v['json'] as String;
    final want = v['bytes'] as String;
    final got = _toHex(fromJson(json));
    _check(got == want, 'fromJson($json) = $got, want $want');
  }

  // 2. JSON decode: toJson(bytes) == json.
  for (final raw in vectors) {
    final v = (raw as Map).cast<String, dynamic>();
    if (!v.containsKey('json')) continue;
    final json = v['json'] as String;
    final bytes = v['bytes'] as String;
    final got = toJson(_fromHex(bytes));
    _check(got == json, 'toJson($bytes) = $got, want $json');
  }

  // 3. Build encode: encode(build(op)) == bytes.
  var buildCount = 0;
  for (final raw in vectors) {
    final v = (raw as Map).cast<String, dynamic>();
    if (!v.containsKey('build')) continue;
    buildCount++;
    final op = (v['build'] as Map).cast<String, dynamic>();
    final want = v['bytes'] as String;
    final got = _toHex(_buildOne(op));
    _check(got == want, 'build $op = $got, want $want');
  }

  // 4. Build transcode: transcode(bytes) == bytes.
  for (final raw in vectors) {
    final v = (raw as Map).cast<String, dynamic>();
    if (!v.containsKey('build')) continue;
    final bytes = v['bytes'] as String;
    final got = _toHex(transcode(_fromHex(bytes)));
    _check(got == bytes, 'transcode($bytes) = $got');
  }

  // 5. Semantic corpus: semanticOrder(a, b) == order.
  final semantic = _loadCorpus('semantic_vectors.json');
  for (final raw in semantic) {
    final pr = (raw as Map).cast<String, dynamic>();
    final a = pr['a'] as String;
    final b = pr['b'] as String;
    final want = (pr['order'] as num).toInt();
    final got = semanticOrder(_fromHex(a), _fromHex(b));
    _check(got == want, 'semanticOrder($a, $b) = $got, want $want');
  }

  // 6. Malformed corpus: every hostile encoding must be rejected with the port's
  //    own decode error (StrupleException) when the whole stream is decoded — never
  //    a RangeError / other native exception, and never a silent (no-throw) decode.
  final malformed = _loadMalformed();
  var malformedRejected = 0;
  for (final raw in malformed) {
    final c = (raw as Map).cast<String, dynamic>();
    final hex = c['hex'] as String;
    final note = c['note'] as String? ?? '';
    final bytes = _fromHex(hex);
    var rejected = false;
    try {
      // transcode walks and fully decodes the entire element stream.
      transcode(bytes);
    } on StrupleException {
      rejected = true; // the port's own clean decode error — the required outcome
    } catch (_) {
      rejected = false; // RangeError or any other type is a hard failure
    }
    _check(rejected, 'malformed [$hex] ($note) rejected with StrupleException');
    if (rejected) malformedRejected++;
  }
  stdout.writeln(
      'conformance: malformed: $malformedRejected/${malformed.length} rejected');

  stdout.writeln('conformance: $jsonCount json vectors (both directions), '
      '$buildCount build vectors (both directions), '
      '${semantic.length} semantic pairs');
  stdout.writeln('conformance: ${_checks - _failures}/$_checks checks passed');
  if (_failures > 0) {
    stderr.writeln('conformance: $_failures FAILURES');
    exit(1);
  }
  stdout.writeln('conformance: ALL PASS');
}
